# main.py — minimal agent endpoint (runs inside the container as-is)
from fastapi import FastAPI
import anthropic, os

app = FastAPI()
client = anthropic.Anthropic()  # reads ANTHROPIC_API_KEY from env

@app.get("/health")
def health():
    return {"status": "ok"}

@app.post("/run")
def run_agent(prompt: str):
    message = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        messages=[{"role": "user", "content": prompt}],
    )
    return {"response": message.content[0].text}

# ECS: reference Secrets Manager ARN in task definition
# (secret is injected as an env var only within the task, never stored in the image)
{
  "secrets": [
    {
      "name": "ANTHROPIC_API_KEY",
      "valueFrom": "arn:aws:secretsmanager:us-east-1:123456789:secret:prod/agent-api/anthropic-key"
    }
  ]
}
